module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);

    // Define the states
    parameter [2:0] S0 = 3'b000, S1 = 3'b001, S2 = 3'b010, S3 = 3'b011, S4 = 3'b100;

    // Current and next state registers
    reg [2:0] current_state, next_state;

    // State transition logic
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            current_state <= S0;
        end else begin
            current_state <= next_state;
        end
    end

    // Next state logic
    always @(*) begin
        case (current_state)
            S0: begin
                if (IN) next_state = S1;
                else next_state = S0;
            end
            S1: begin
                if (IN) next_state = S1;
                else next_state = S2;
            end
            S2: begin
                if (IN) next_state = S1;
                else next_state = S3;
            end
            S3: begin
                if (IN) next_state = S4;
                else next_state = S0;
            end
            S4: begin
                if (IN) next_state = S1;
                else next_state = S0;
            end
            default: next_state = S0;
        endcase
    end

    // Output logic
    assign MATCH = (current_state == S4) && IN;

endmodule
